 22	import { GraphToolbarActions } from '../../../actions/GraphToolbarActions';
 23	import { GraphSettings } from './GraphSettings';
 24	import { GraphType, NodeParamsType, EdgeLabelMode, SummaryData, TrafficRate, RankMode } from '../../../types/Graph';
 25	import { router, HistoryManager, URLParam, location } from '../../../app/History';
 26	import { Namespace, namespacesFromString, namespacesToString } from '../../../types/Namespace';
 27	import { KialiDispatch } from '../../../types/Redux';
 28	import { NamespaceActions } from '../../../actions/NamespaceAction';
 29	import { GraphActions } from '../../../actions/GraphActions';
 30	import { GraphTourStops } from 'pages/Graph/GraphHelpTour';
 31	import { TourStop } from 'components/Tour/TourStop';
 32	import { KialiIcon } from 'config/KialiIcon';
 33	import { Replay } from 'components/Time/Replay';
 34	import { UserSettingsActions } from 'actions/UserSettingsActions';
 35	import { GraphSecondaryMasthead } from './GraphSecondaryMasthead';
 36	import { INITIAL_USER_SETTINGS_STATE } from 'reducers/UserSettingsState';
 37	import { GraphReset } from './GraphReset';
 38	import { GraphFind } from './GraphFind';
 39	import { kialiStyle } from 'styles/StyleUtils';
 40	import { isParentKiosk, kioskContextMenuAction } from 'components/Kiosk/KioskActions';
 41	import { GraphElement } from '@patternfly/react-topology';
 42	
 43	type ReduxStateProps = {
 44	  activeNamespaces: Namespace[];
 45	  edgeLabels: EdgeLabelMode[];
 46	  graphType: GraphType;
 47	  kiosk: string;
 48	  node?: NodeParamsType;
 49	  rankBy: RankMode[];
 50	  replayActive: boolean;
 51	  showIdleNodes: boolean;
 52	  summaryData: SummaryData | null;
 53	  trafficRates: TrafficRate[];
 54	};
 55	
 56	type ReduxDispatchProps = {
 57	  setActiveNamespaces: (activeNamespaces: Namespace[]) => void;
 58	  setEdgeLabels: (edgeLabels: EdgeLabelMode[]) => void;
 59	  setGraphType: (graphType: GraphType) => void;
 60	  setIdleNodes: (idleNodes: boolean) => void;
 61	  setNode: (node?: NodeParamsType) => void;
 62	  setRankBy: (rankLabels: RankMode[]) => void;
 63	  setTrafficRates: (rates: TrafficRate[]) => void;
 64	  toggleReplayActive: () => void;
 65	};
