 67	type ReduxProps = ReduxStateProps & ReduxDispatchProps;
 68	
 69	type GraphToolbarProps = ReduxProps & {
 70	  controller?: any;
 71	  disabled: boolean;
 72	  elementsChanged: boolean;
 73	  onToggleHelp: () => void;
 74	};
 75	
 76	const helpStyle = kialiStyle({
 77	  marginRight: '0.5rem',
 78	  alignSelf: 'center'
 79	});
 80	
 81	class GraphToolbarComponent extends React.PureComponent<GraphToolbarProps> {
 82	  static contextTypes = {
 83	    router: () => null
 84	  };
 85	
 86	  constructor(props: GraphToolbarProps) {
 87	    super(props);
 88	    // Let URL override current redux state at construction time. Update URL as needed.
 89	    const urlParams = new URLSearchParams(location.getSearch());
 90	
 91	    const urlEdgeLabels = HistoryManager.getParam(URLParam.GRAPH_EDGE_LABEL, urlParams);
 92	    if (!!urlEdgeLabels) {
 93	      if (urlEdgeLabels !== props.edgeLabels.join(',')) {
 94	        props.setEdgeLabels(urlEdgeLabels.split(',') as EdgeLabelMode[]);
 95	      }
 96	    } else if (props.setEdgeLabels.length > 0) {
 97	      HistoryManager.setParam(URLParam.GRAPH_EDGE_LABEL, props.edgeLabels.join(','));
 98	    }
 99	
100	    const urlRankLabels = HistoryManager.getParam(URLParam.GRAPH_RANK_BY, urlParams);
101	    if (!!urlRankLabels) {
102	      if (urlRankLabels !== props.rankBy.join(',')) {
103	        props.setRankBy(urlRankLabels.split(',') as RankMode[]);
104	      }
105	    } else if (props.setRankBy.length > 0) {
106	      HistoryManager.setParam(URLParam.GRAPH_RANK_BY, props.rankBy.join(','));
107	    }
108	
109	    const urlReplayActive = HistoryManager.getBooleanParam(URLParam.GRAPH_REPLAY_ACTIVE);
110	    if (urlReplayActive !== undefined) {
111	      if (urlReplayActive !== this.props.replayActive) {
112	        this.props.toggleReplayActive();
113	      }
114	    } else if (this.props.replayActive !== INITIAL_USER_SETTINGS_STATE.replayActive) {
115	      HistoryManager.setParam(URLParam.GRAPH_REPLAY_ACTIVE, String(this.props.replayActive));
116	    }
117	
118	    const urlGraphTraffic = HistoryManager.getParam(URLParam.GRAPH_TRAFFIC, urlParams);
119	    if (!!urlGraphTraffic) {
120	      if (urlGraphTraffic !== props.trafficRates.join(',')) {
121	        props.setTrafficRates(urlGraphTraffic.split(',') as TrafficRate[]);
122	      }
123	    } else if (props.trafficRates.length > 0) {
124	      HistoryManager.setParam(URLParam.GRAPH_TRAFFIC, props.trafficRates.join(','));
125	    }
126	
127	    const urlGraphType = HistoryManager.getParam(URLParam.GRAPH_TYPE, urlParams) as GraphType;
128	    if (!!urlGraphType) {
129	      if (urlGraphType !== props.graphType) {
130	        props.setGraphType(urlGraphType);
131	      }
132	    } else {
133	      HistoryManager.setParam(URLParam.GRAPH_TYPE, String(this.props.graphType));
134	    }
135	
136	    const urlNamespaces = HistoryManager.getParam(URLParam.NAMESPACES, urlParams);
137	    if (!!urlNamespaces) {
138	      if (urlNamespaces !== namespacesToString(props.activeNamespaces)) {
139	        props.setActiveNamespaces(namespacesFromString(urlNamespaces));
140	      }
141	    } else if (props.activeNamespaces.length > 0) {
142	      HistoryManager.setParam(URLParam.NAMESPACES, namespacesToString(props.activeNamespaces));
143	    }
144	  }
145	
146	  componentDidUpdate(prevProps: GraphToolbarProps): void {
147	    // ensure redux state and URL are aligned
148	    if (String(prevProps.edgeLabels) !== String(this.props.edgeLabels)) {
149	      if (this.props.edgeLabels?.length === 0) {
150	        HistoryManager.deleteParam(URLParam.GRAPH_EDGE_LABEL);
151	      } else {
152	        HistoryManager.setParam(URLParam.GRAPH_EDGE_LABEL, String(this.props.edgeLabels));
153	      }
154	    }
155	
156	    if (String(prevProps.rankBy) !== String(this.props.rankBy)) {
157	      if (this.props.rankBy?.length === 0) {
158	        HistoryManager.deleteParam(URLParam.GRAPH_RANK_BY);
159	      } else {
160	        HistoryManager.setParam(URLParam.GRAPH_RANK_BY, String(this.props.rankBy));
161	      }
162	    }
163	
164	    if (namespacesToString(prevProps.activeNamespaces) !== namespacesToString(this.props.activeNamespaces)) {
165	      if (this.props.activeNamespaces?.length === 0) {
166	        HistoryManager.deleteParam(URLParam.NAMESPACES);
167	      } else {
168	        HistoryManager.setParam(URLParam.NAMESPACES, namespacesToString(this.props.activeNamespaces));
169	      }
170	    }
171	
172	    if (String(prevProps.replayActive) !== String(this.props.replayActive)) {
173	      if (this.props.replayActive === INITIAL_USER_SETTINGS_STATE.replayActive) {
174	        HistoryManager.deleteParam(URLParam.GRAPH_REPLAY_ACTIVE);
175	      } else {
176	        HistoryManager.setParam(URLParam.GRAPH_REPLAY_ACTIVE, String(this.props.replayActive));
177	      }
178	    }
179	
180	    if (String(prevProps.trafficRates) !== String(this.props.trafficRates)) {
181	      if (this.props.trafficRates?.length === 0) {
182	        HistoryManager.deleteParam(URLParam.GRAPH_TRAFFIC);
183	      } else {
184	        HistoryManager.setParam(URLParam.GRAPH_TRAFFIC, String(this.props.trafficRates));
185	      }
186	    }
187	
188	    if (prevProps.graphType !== this.props.graphType) {
