212	              <ToolbarItem style={{ margin: 0 }}>
213	                <Tooltip key={'graph-tour-help-ot'} position={TooltipPosition.right} content={'Back to full graph'}>
214	                  <Button variant={ButtonVariant.link} onClick={this.handleNamespaceReturn}>
215	                    <KialiIcon.Back />
216	                  </Button>
217	                </Tooltip>
218	              </ToolbarItem>
219	            )}
220	
221	            <ToolbarItem style={{ margin: 0 }}>
222	              <TourStop info={GraphTourStops.Display}>
223	                <GraphSettings graphType={this.props.graphType} disabled={this.props.disabled} />
224	              </TourStop>
225	            </ToolbarItem>
226	
227	            <ToolbarItem>
228	              <GraphFind controller={this.props.controller} elementsChanged={this.props.elementsChanged} />
229	            </ToolbarItem>
230	
231	            <ToolbarItem style={{ marginLeft: 'auto', alignSelf: 'center' }}>
