235	                    id="graph-tour"
236	                    variant={ButtonVariant.link}
237	                    className={helpStyle}
238	                    onClick={this.props.onToggleHelp}
239	                    isInline
240	                  >
241	                    <KialiIcon.Help />
242	                    <span style={{ marginLeft: '5px' }}>Help</span>
243	                  </Button>
244	                </TourStop>
