255	  private handleNamespaceReturn = (): void => {
256	    const route = 'graph';
257	    if (
258	      !this.props.summaryData ||
259	      (this.props.summaryData.summaryType !== 'node' && this.props.summaryData.summaryType !== 'box')
260	    ) {
261	      const returnUrl = `/${route}/namespaces`;
262	
263	      if (isParentKiosk(this.props.kiosk)) {
264	        kioskContextMenuAction(returnUrl);
265	      } else {
266	        router.navigate(returnUrl);
267	      }
268	
269	      return;
270	    }
271	
272	    const elem = this.props.summaryData!.summaryTarget as GraphElement;
273	    const selector = elem.getId();
274	
275	    this.props.setNode(undefined);
276	
277	    const returnUrl = `/${route}/namespaces?${URLParam.FOCUS_SELECTOR}=${encodeURI(selector)}`;
278	
279	    if (isParentKiosk(this.props.kiosk)) {
280	      kioskContextMenuAction(returnUrl);
281	    } else {
282	      router.navigate(returnUrl);
283	    }
284	  };
285	}
