287	const mapStateToProps = (state: KialiAppState): ReduxStateProps => ({
288	  activeNamespaces: activeNamespacesSelector(state),
289	  edgeLabels: edgeLabelsSelector(state),
290	  graphType: graphTypeSelector(state),
291	  kiosk: state.globalState.kiosk,
292	  node: state.graph.node,
293	  rankBy: state.graph.toolbarState.rankBy,
294	  replayActive: replayActiveSelector(state),
295	  showIdleNodes: showIdleNodesSelector(state),
296	  summaryData: state.graph.summaryData,
297	  trafficRates: trafficRatesSelector(state)
298	});
299	
300	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxDispatchProps => {
301	  return {
302	    setActiveNamespaces: bindActionCreators(NamespaceActions.setActiveNamespaces, dispatch),
303	    setEdgeLabels: bindActionCreators(GraphToolbarActions.setEdgeLabels, dispatch),
304	    setGraphType: bindActionCreators(GraphToolbarActions.setGraphType, dispatch),
305	    setIdleNodes: bindActionCreators(GraphToolbarActions.setIdleNodes, dispatch),
306	    setNode: bindActionCreators(GraphActions.setNode, dispatch),
307	    setRankBy: bindActionCreators(GraphToolbarActions.setRankBy, dispatch),
308	    setTrafficRates: bindActionCreators(GraphToolbarActions.setTrafficRates, dispatch),
309	    toggleReplayActive: bindActionCreators(UserSettingsActions.toggleReplayActive, dispatch)
310	  };
311	};
312	
313	export const GraphToolbar = connect(mapStateToProps, mapDispatchToProps)(GraphToolbarComponent);

